svg.script:

var elem;
var svgdoc;
function init(evt) {
   svgdoc = evt.target.ownerDocument;
   elem = svgdoc.getElementById("toShow");
   elem.addEventListener("mouseover", changeColor, false);
   elem.addEventListener("mouseout", changeColor, false);
}

function changeColor(evt) {
  var crc = evt.target;
  var actColor = crc.getAttribute("style");
  if (actColor=="fill:green") {
     crc.setAttribute("style", "fill:red");
  } else {
     crc.setAttribute("style", "fill:green");
  }
}
